    [v("עֵינַי","i miei occhi (dual + suff. 1cs)"), v("כִּלּוּ","hanno consumato (pi'el perf. 3cp di כ-ל-ה)"), v("אֶל","verso (preposizione di direzione)"), v("יְשׁוּעָתֶךָ","la tua salvezza (-kha suff. 2ms)"), v("acrostico","Salmo 119: ogni strofa inizia con lettera dell'alef-bet")],
