   [v("bilitterale","segno che rappresenta due consonanti"), v("𓌀 (wn)","il coniglio — suono wn"), v("𓌃 (mr)","il canale — suono mr"), v("𓆎 (ms)","tre volpi — suono ms"), v("complemento fonetico","unilitterale che ripete l'ultima consonante del bilitterale"), v("𓊹 (nTr)","segno di 'dio, divino'")],
